log "ONNX features: $(cat /proc/cpuinfo | grep -o 'avx2\|avx512' | sort -u | tr '\n' ' ')"

# Model discovery
log "Available models:"
xf models list --json 2>/dev/null | jq -r '.[] | "  \(.name) [\(.category)]"' | tee -a "$LOG"

# Single model benchmark
log "Running single-model benchmark..."
xf benchmark --model=all-MiniLM-L6-v2 \
    --corpus=tests/fixtures/benchmark_corpus.json \
    --output=/tmp/bench_single.json 2>&1 | tee -a "$LOG"
[ -f /tmp/bench_single.json ] && { log "  Output file created"; ((PASS++)); } || { log "  No output"; ((FAIL++)); }

# Verify BenchmarkResult schema
log "Validating result schema..."
jq -e '.results[0].model_name' /tmp/bench_single.json >/dev/null && { log "  model_name present"; ((PASS++)); } || ((FAIL++))
jq -e '.results[0].category' /tmp/bench_single.json >/dev/null && { log "  category present"; ((PASS++)); } || ((FAIL++))
jq -e '.results[0].speed.warm_latency_p50_ms' /tmp/bench_single.json >/dev/null && { log "  speed metrics present"; ((PASS++)); } || ((FAIL++))
jq -e '.results[0].quality.ndcg_at_10' /tmp/bench_single.json >/dev/null && { log "  quality metrics present"; ((PASS++)); } || ((FAIL++))

# Comparison mode
log "Running comparison benchmark..."
xf benchmark --compare --models=miniLM,static-mrl \
    --corpus=tests/fixtures/benchmark_corpus.json \
    --output=/tmp/bench_compare.json 2>&1 | tee -a "$LOG"
NRESULTS=$(jq '.results | length' /tmp/bench_compare.json 2>/dev/null)
[ "$NRESULTS" -ge 2 ] && { log "  Comparison has $NRESULTS results"; ((PASS++)); } || { log "  Too few results: $NRESULTS"; ((FAIL++)); }

# MRL sweep
log "Running MRL sweep..."
xf benchmark --model=static-retrieval-mrl-en-v1 --dimensions=256,512,768 \
    --corpus=tests/fixtures/benchmark_corpus.json \
    --output=/tmp/bench_mrl.json 2>&1 | tee -a "$LOG"
MRL_DIMS=$(jq '.results[0].mrl_dims_tested | length' /tmp/bench_mrl.json 2>/dev/null)
[ "$MRL_DIMS" -ge 3 ] && { log "  MRL sweep: $MRL_DIMS dimensions tested"; ((PASS++)); } || { log "  MRL sweep incomplete"; ((FAIL++)); }

# Reranker benchmark
log "Running reranker benchmark..."
xf benchmark --reranker=flashrank \
    --corpus=tests/fixtures/benchmark_corpus.json \
    --output=/tmp/bench_rerank.json 2>&1 | tee -a "$LOG"

# Reliability: error_rate and is_reliable
log "Checking reliability fields..."
ERROR_RATE=$(jq '.results[0].errors / .results[0].total_requests' /tmp/bench_single.json 2>/dev/null)
log "  Error rate: $ERROR_RATE"

log "========================="
log "Results: $PASS passed, $FAIL failed"
exit $FAIL
