+        let query_emb = embedder.embed_batch(&[query.text.as_str()])?;
+        let query_vec = &query_emb[0];
+
+        // Compute cosine similarities (embeddings should be normalized)
+        let mut scores: Vec<(usize, f32)> = doc_embeddings
+            .iter()
+            .enumerate()
+            .map(|(i, doc_emb)| {
